CharacterReader(String input) {
        Validate.notNull(input);

        this.input = input;
        this.length = input.length();
        this.pos = 0;
    }

String consumeToEnd() {
        if (pos >= length) return "";
        String data = input.substring(pos, length);
        pos = length;
        return data;
    }
